using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);

builder.Services.AddControllers();

// Train the model at startup
builder.Services.AddHostedService<ModelTrainingService>();

// Thread-safe pooled prediction engine — reloads if model.zip changes
var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "model.zip");
builder.Services.AddPredictionEnginePool<TicketData, TicketPrediction>()
    .FromFile(modelPath, watchForChanges: true);

var app = builder.Build();
app.MapControllers();
app.Run();

